// ============================================================
// Validação e enriquecimento do payload recebido do ESP32
// Garante que todos os campos obrigatórios existem
// antes de distribuir para os nós de UI
// ============================================================

var payload = msg.payload;

// Validação mínima dos campos esperados
if (typeof payload !== 'object' || payload === null) {
    node.warn('[CardioIA] Payload inválido recebido — ignorando mensagem');
    return null;
}

// Garantir campos com valores padrão seguros
var bpm         = (typeof payload.bpm         === 'number') ? payload.bpm         : 0;
var temperatura = (typeof payload.temperatura  === 'number') ? payload.temperatura  : 0;
var umidade     = (typeof payload.umidade      === 'number') ? payload.umidade      : 0;
var alerta      = (typeof payload.alerta       === 'boolean')? payload.alerta       : false;
var origem      = (typeof payload.origem       === 'string') ? payload.origem       : 'desconhecida';
var timestamp   = (typeof payload.timestamp    !== 'undefined') ? payload.timestamp : Date.now();

// Recalcular alertas individualmente (para mensagem descritiva)
var alertaBPM         = bpm > 120;
var alertaTemperatura = temperatura > 38;
var alertaUmidade     = umidade < 40 || umidade > 80;

// Hora local formatada para exibição
var agora = new Date();
var horaLocal = agora.toLocaleTimeString('pt-BR');

// Montar payload enriquecido
msg.payload = {
    bpm:               bpm,
    temperatura:       temperatura,
    umidade:           umidade,
    alerta:            alerta,
    origem:            origem,
    timestamp:         timestamp,
    horaLocal:         horaLocal,
    alertaBPM:         alertaBPM,
    alertaTemperatura: alertaTemperatura,
    alertaUmidade:     alertaUmidade
};

return msg;

// ============================================================
// Distribuidor: cria cópias do payload para cada saída
// Saída 1 → Gráfico BPM (chart)
// Saída 2 → Gauge Temperatura
// Saída 3 → Gauge Umidade
// Saída 4 → Cards de valores atuais
// Saída 5 → Lógica de alerta médico
// ============================================================

var p = msg.payload;

// Saída 1: BPM para o gráfico de série temporal
var msgBPM = { payload: p.bpm, topic: 'BPM', horaLocal: p.horaLocal };

// Saída 2: Temperatura para gauge
var msgTemp = { payload: p.temperatura };

// Saída 3: Umidade para gauge
var msgUmid = { payload: p.umidade };

// Saída 4: Dados completos para os cards de texto
var msgCards = { payload: p };

// Saída 5: Dados completos para lógica de alerta
var msgAlerta = { payload: p };

return [msgBPM, msgTemp, msgUmid, msgCards, msgAlerta];

// ============================================================
// Formata os cards de texto com valores atuais e origem
// Saída 1 → Card BPM
// Saída 2 → Card Temperatura
// Saída 3 → Card Umidade
// Saída 4 → Card Origem/Fonte
// ============================================================

var p = msg.payload;

// Card BPM com indicador de alerta
var iconeBPM  = p.alertaBPM ? '⚠️' : '💚';
var msgBPMCard = { payload: iconeBPM + ' ' + p.bpm + ' BPM' };

// Card Temperatura
var iconeTemp = p.alertaTemperatura ? '🔴' : '🟢';
var msgTempCard = { payload: iconeTemp + ' ' + p.temperatura.toFixed(1) + ' °C' };

// Card Umidade
var iconeUmid = p.alertaUmidade ? '🔶' : '🟢';
var msgUmidCard = { payload: iconeUmid + ' ' + p.umidade.toFixed(1) + ' %' };

// Card Origem (tempo_real vs SYNC->CLOUD)
var origemLabel = (p.origem === 'tempo_real') ? '📡 Tempo Real' : '🔄 Sincronizado (Offline→Cloud)';
var msgOrigem = { payload: origemLabel + ' — ' + p.horaLocal };

return [msgBPMCard, msgTempCard, msgUmidCard, msgOrigem];

// ============================================================
// Determina o status de alerta e monta mensagem descritiva
// Classifica qual parâmetro causou o alerta
// Saída 1 → Texto do status (NORMAL / ALERTA ATIVO)
// Saída 2 → Mensagem descritiva do alerta
// Saída 3 → Controle da cor do painel (0=verde, 1=vermelho)
// Saída 4 → Histórico de eventos (apenas quando alerta=true)
// ============================================================

var p = msg.payload;

var statusTexto;
var mensagemDescritiva;
var corIndicador;   // 0 = NORMAL (verde), 1 = ALERTA (vermelho)
var msgHistorico = null;

if (p.alerta === true) {
    // Montar lista de parâmetros em alerta
    var parametrosAlerta = [];

    if (p.alertaBPM) {
        parametrosAlerta.push('TAQUICARDIA — BPM: ' + p.bpm);
    }
    if (p.alertaTemperatura) {
        parametrosAlerta.push('FEBRE — Temp: ' + p.temperatura.toFixed(1) + '°C');
    }
    if (p.alertaUmidade) {
        var motivo = (p.umidade < 40) ? 'muito baixa' : 'muito alta';
        parametrosAlerta.push('UMIDADE ' + motivo.toUpperCase() + ' — ' + p.umidade.toFixed(1) + '%');
    }

    // Fallback: se campo alerta=true mas nenhum critério individual disparou
    if (parametrosAlerta.length === 0) {
        parametrosAlerta.push('ALERTA DETECTADO PELO DISPOSITIVO');
    }

    statusTexto       = '🚨 ALERTA ATIVO';
    mensagemDescritiva = parametrosAlerta.join(' | ');
    corIndicador      = 1;

    // Registrar no histórico
    msgHistorico = {
        payload: '[' + p.horaLocal + '] ⚠️ ' + mensagemDescritiva
    };

} else {
    statusTexto        = '✅ NORMAL';
    mensagemDescritiva = 'Todos os parâmetros dentro dos limites normais.';
    corIndicador       = 0;
}

var msgStatus     = { payload: statusTexto };
var msgMensagem   = { payload: mensagemDescritiva };
var msgCor        = { payload: corIndicador };

return [msgStatus, msgMensagem, msgCor, msgHistorico];
